+import { NonExhaustiveError } from './errors';
+import { matchPattern } from './internals/helpers';
+import * as symbols from './internals/symbols';
+import type { MatchEach } from './types/MatchEach';
+
+type Clause = { patterns?: unknown[]; predicate?: (value: unknown) => unknown; handler: (selection: unknown, value: unknown) => unknown };
+type Step = { kind: 'clause'; clause: Clause } | { kind: 'tap'; callback: (result: unknown) => unknown };
+
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, input, output>;
+export function matchEach(value?: unknown): any {
+  return new MatchEachExpression(value, arguments.length === 1, []);
+}
+
+class MatchEachExpression {
+  constructor(private value: unknown, private hasValue: boolean, private steps: Step[]) {}
+
+  with(...args: any[]) {
+    const handler = args[args.length - 1];
+    let patterns = [args[0]];
+    let predicate: ((value: unknown) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns = args.slice(0, -1);
+    return this.add({ kind: 'clause', clause: { patterns, predicate, handler } });
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown) {
+    return this.add({ kind: 'clause', clause: { predicate, handler } });
+  }
+
+  tap(callback: (result: unknown) => unknown) { return this.add({ kind: 'tap', callback }); }
+  returnType() { return this; }
+  narrow() { return this; }
+
+  otherwise(handler: (value: unknown) => unknown) {
+    const results = this.evaluate(this.value);
+    return results.length ? results : [handler(this.value)];
+  }
+
+  exhaustive(fallback = defaultCatcher) {
+    const results = this.evaluate(this.value);
+    return results.length ? results : [fallback(this.value)];
+  }
+  run() { return this.exhaustive(); }
+
+  toFunction() { return (input: unknown) => this.require(input); }
+  toExhaustiveFunction() { return (input: unknown) => this.require(input); }
+  toPartialFunction() { return (input: unknown) => { const results = this.evaluate(input); return results.length ? results : undefined; }; }
+
+  private add(step: Step) { return new MatchEachExpression(this.value, this.hasValue, [...this.steps, step]); }
+  private require(input: unknown) { const results = this.evaluate(input); if (!results.length) throw new NonExhaustiveError(input); return results; }
+  private evaluate(input: unknown): unknown[] {
+    const results: unknown[] = [];
+    for (const step of this.steps) {
+      if (step.kind === 'tap') { results.forEach(step.callback); continue; }
+      const { patterns, predicate, handler } = step.clause;
